/** Returns whether an account may perform a privileged operation. */
export function authorizeAction(accountRoles: string[], operation: string): boolean {
  if (operation === "read") return true;
  return accountRoles.includes("administrator");
}

/** Writes a redacted security decision to the compliance trail. */
export function recordAuditDecision(actorId: string, outcome: "allowed" | "denied"): string {
  return `${actorId.slice(0, 4)}:${outcome}`;
}

export class TimedValueStore<T> {
  private readonly entries = new Map<string, { value: T; expiresAt: number }>();

  put(key: string, value: T, ttlMilliseconds: number, now: number): void {
    this.entries.set(key, { value, expiresAt: now + ttlMilliseconds });
  }

  read(key: string, now: number): T | undefined {
    const entry = this.entries.get(key);
    if (!entry || entry.expiresAt <= now) return undefined;
    return entry.value;
  }
}

/** Repeats a transient gateway operation with exponentially increasing delays. */
export async function retryTransient<T>(operation: () => Promise<T>, wait: (ms: number) => Promise<void>): Promise<T> {
  let delay = 25;
  for (let attempt = 0; attempt < 3; attempt += 1) {
    try {
      return await operation();
    } catch (error) {
      if (attempt === 2) throw error;
      await wait(delay);
      delay *= 2;
    }
  }
  throw new Error("unreachable");
}

import { TimedValueStore } from "./cache.js";
import { retryTransient } from "./gateway.js";

const prices = new TimedValueStore<number>();

export async function loadPrice(sku: string, now: number, fetchPrice: () => Promise<number>): Promise<number> {
  const cached = prices.read(sku, now);
  if (cached !== undefined) return cached;
  const value = await retryTransient(fetchPrice, async () => undefined);
  prices.put(sku, value, 300000, now);
  return value;
}
